#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
struct Node{
	int to,val;
};
int n,q,d[N],c[N],dist[N],f[N][17];
vector<Node> g[N];
void set_things(){
	stack<int> s;
	for(int i=1;i<=n;i++){
		while(s.size() && d[s.top()]<d[i])
			f[s.top()][0]=i,g[s.top()].push_back({i,c[s.top()]}),g[i].push_back({s.top(),c[s.top()]}),s.pop();
		s.push(i);
	}
	while(s.size())
		g[s.top()].push_back({0,c[s.top()]}),g[0].push_back({s.top(),c[s.top()]}),s.pop();
	queue<int> b;
	b.push(0);
	while(b.size()){
		int u=b.front(),len=g[u].size();
		b.pop();
		for(int i=0;i<len;i++)
			if(g[u][i].to && !dist[g[u][i].to])
				dist[g[u][i].to]=dist[u]+g[u][i].val,b.push(g[u][i].to);
	}
	for(int i=n;i;i--)
		for(int j=1;j<17 && f[f[i][j-1]][j-1];j++)
			f[i][j]=f[f[i][j-1]][j-1];
}
int main(){
    cin>>n>>q;
    for(int i=1;i<=n;i++)
    	cin>>d[i]>>c[i];
    set_things();
    /*for(int i=1;i<=n;i++)
    	cout<<dist[i]<<' ';
    cout<<'\n';
    for(int i=1;i<=n;i++){
    	for(int j=0;j<17;j++)
    		cout<<f[i][j]<<' ';
    	cout<<'\n';
	}*/
    while(q--){
    	int r,v;
    	cin>>r>>v;
    	int p=r;
    	for(int i=16;i>=0 && p;i--)
    		if(dist[p]-dist[f[p][i]]<v)
    			v-=dist[p]-dist[f[p][i]],p=f[p][i];
    	cout<<p<<endl;
	}
    return 0;
}
